import { Component, OnInit } from '@angular/core';
import {DomSanitizer} from '@angular/platform-browser';
import { Http } from '@angular/http';
import { Observable, of } from 'rxjs';
import { map, filter, catchError, tap } from 'rxjs/operators';
import * as firebase from 'firebase';

@Component({
  selector: 'app-magnet-extractor',
  templateUrl: './magnet-extractor.component.html',
  styleUrls: ['./magnet-extractor.component.scss']
})
export class MagnetExtractorComponent implements OnInit {

  linkSearch: string = '';
  links: string[] = [];
  searching: boolean = false;
  found: boolean = false;
  total: number = 0;

  constructor(
    private http: Http,
    private sanitizer: DomSanitizer
  ) { }

  ngOnInit() {
    // this.http.get('/assets/posts/magnet-extractor.md').subscribe(r => console.log(r));
  }

  sanitize(url:string){
    return this.sanitizer.bypassSecurityTrustUrl(url);
  }

  retrieveLinks(url: string) {
    if(url.length === 0) {
      alert('Você precisa informar o link');
      return;
    }
    
    this.searching = true;
    this.found = false;

    firebase.analytics().logEvent('magnet_extractor', { url });

    this.http.post('https://us-central1-codesilva-blog.cloudfunctions.net/extract_magnet', {
      url: url
    }).pipe(
      map(response => response.json()),
      catchError((err, caught) => {
        alert(`Houve um erro ao buscar os links em ${url}.\nTente novamente mais tarde ou entre em contato no e-mail: edigleyssonsilva@gmail.com`);
        this.searching = false;
        return of(null);
      }),
      filter(data => data !== null),
      map(json => {
        let linksRetrieved: string[] = json.links.map(link => link);
        return linksRetrieved;
      }),
      tap(links => console.log(links))
    ).subscribe(r => {
      this.links = r;
      this.searching = false;
      this.found=true;
      if(this.links.length === 0) {
        alert(`Não encontramos nada na url ${url}\n\nEsse site é enganoso :/`);
      }
    });
    
  }

}
