import { Component, OnInit, Inject } from '@angular/core';
import { Http } from '@angular/http';
import showdown from 'showdown';
import { ActivatedRoute } from '@angular/router';
import { BlogService } from 'src/app/services/blog.service';
import { PostService } from 'src/app/services/post.service';
import { Post } from 'src/app/models/post';

// Quando salvar o post: substituir tudo que é '\n' por '\\n'
// Quando carregar: substituir tudo que é '\\n' por '\n' antes de converter em HTML

@Component({
  selector: 'app-post',
  templateUrl: './post.component.html',
  styleUrls: ['./post.component.scss']
})
export class PostComponent implements OnInit {

  converter = new showdown.Converter({
    extensions: []
  })
  content: string = '';
  slug: string = '';

  metadata: any = {};
  post: Post;

  constructor(
    private http: Http,
    private activatedRoute: ActivatedRoute,
    private blogService: BlogService,
    private postService: PostService,
  ) {

    this.post = this.postService.currentPost;
    this.postService.getPostContentByDoc(this.post)
      .subscribe(docSnapshot => {
        let data = docSnapshot.data();
        let content = data['content'].replace(/\\n/g, '\n');
        this.content = this.converter.makeHtml(content);
      });
  }

  ngOnInit() {
    window.scrollTo(0,0);
  }

}
