import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router, RouterEvent, NavigationEnd, NavigationStart } from '@angular/router';
import { CategoryService } from 'src/app/services/category.service';
import { Title } from '@angular/platform-browser';


@Component({
  selector: 'app-category',
  templateUrl: './category.component.html',
  styleUrls: ['./category.component.scss']
})
export class CategoryComponent implements OnInit {

  category: any = {
    name: '',
    description: '',
    slug: ''
  };

  constructor(
    private activatedRoute: ActivatedRoute,
    private categoryService: CategoryService,
    private router: Router,
    private titleService: Title
  ) { 
    this.bootstrap();
  }

  ngOnInit() {
       
  }

  /**
   * Faz o carregamento inicial da página
   */
  private bootstrap() {
    this.router.events.subscribe((event: RouterEvent) => {
      if(event instanceof NavigationEnd) {
        let slug: string = this.activatedRoute.snapshot.params['category'];
        this.category = this.categoryService.getCategory(slug);
        this.titleService.setTitle(`CodeSilva - ${this.category.name}`);
      }
    }); 
  }

}
