import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';

import { FrontComponent } from './front.component';
import { HomeComponent } from './pages/home/home.component';
import { PostComponent } from '../pages/post/post.component';
import { CategoryComponent } from './pages/category/category.component';
import { AboutComponent } from './pages/about/about.component';
import { EbookComponent } from '../pages/lp/ebook/ebook.component';
import { EbooksComponent } from './pages/ebooks/ebooks.component';
import { MagnetExtractorComponent } from '../pages/magnet-extractor/magnet-extractor.component';
import { PlaygroundComponent } from './pages/playground/playground.component';

const routes: Routes = [
  {
    path: '',
    component: FrontComponent,
    children: [
      {
        path: '',
        component: HomeComponent
      },

      {
        path: 'about',
        component: AboutComponent
      },

      {
        path: 'categorias',
        component: CategoryComponent
      },

      { path: 'ebooks', pathMatch: 'full', component: EbooksComponent },
      {
        path: 'playground',
        children: [
          {
            path: '',
            component: PlaygroundComponent,
          },

          { path: 'magnet-extractor', component: MagnetExtractorComponent },
        ]
      },

      { path: 'magnet-extractor', pathMatch: 'full', component: MagnetExtractorComponent },

      {
        path: 'p',
        children: [
          { path: '', pathMatch: 'full', redirectTo: '/' },
          { path: ':slug', component: PostComponent }
        ]
      },

      {
        path: 'gerando-apk-ionic',
        pathMatch: 'full',
        component: EbookComponent
      },

      {
        path: 'ebook',
        children: [
          {
            path: 'gerando-apk-ionic',
            pathMatch: 'full',
            component: EbookComponent
          },
        ]
      }
    ],
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class FrontRoutingModule { }
