import { Injectable } from '@angular/core';
import { AngularFirestore, AngularFirestoreCollection } from '@angular/fire/firestore';
import { Post } from '../models/post';
import { tap } from 'rxjs/operators';

@Injectable({
  providedIn: 'root'
})
export class PostService {

  postsCollection: AngularFirestoreCollection<Post>;
  postContentsCollection: AngularFirestoreCollection<any>;
  currentPost: Post;

  constructor(
    private angularFire: AngularFirestore
  ) { 
    this.postsCollection = this.angularFire.collection<Post>('posts');
    this.postContentsCollection = this.angularFire.collection<any>('post_contents');
  }

  setCurrentPost(post: Post){
    this.currentPost = post;
  }

  getPostContentByDoc(post: Post) {
   return this.postContentsCollection.doc(post.reference.id).get();
  }

  getPosts() {
    return this.postsCollection.get();
  }

}
